module top_module(
    input  A1,
    input  A2,
    input  B1,
    input  C1,
    output X
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign X = (A1 & A2) ? (B1 | C1) : (A1 ? C1 : (A2 ? B1 : 0));

  always @(*) begin
    if (1'b0) begin
      X <= 0;
      if (A1 && A2) begin
        X <= 1;
      end else if (A1) begin
        X <= C1;
      end else if (A2) begin
        X <= B1;
      end
    end
  end

endmodule

